/**
 * One-time / regen: writes data/cities.json with 100 cities (USD-normalized costs).
 * Run: node scripts/build-initial-cities.mjs
 */
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const OUT = path.join(__dirname, '..', 'data', 'cities.json');

/** Reference costs (USD) at costIndex 78 — scaled for other cities */
const BASE = {
  monthlyBudget: {
    single: { min: 2400, max: 3800 },
    couple: { min: 3800, max: 5800 },
    family: { min: 5500, max: 8500 }
  },
  costs: {
    rentCenterStudio: { min: 1400, max: 2100 },
    rentCenterOneBed: { min: 1800, max: 2800 },
    rentOutsideOneBed: { min: 950, max: 1500 },
    utilities: { min: 75, max: 145 },
    internet: { min: 30, max: 50 },
    groceries: { min: 380, max: 570 },
    restaurant: { min: 15, max: 25 },
    restaurantMid: { min: 50, max: 90 },
    coffee: { min: 4, max: 6 },
    transport: { min: 95, max: 115 },
    gym: { min: 35, max: 65 },
    cinema: { min: 14, max: 18 }
  },
  scores: {
    overall: 7.2,
    housing: 5.1,
    safety: 8.9,
    healthcare: 8.5,
    education: 8.2,
    environment: 8.8,
    economy: 7.5,
    culture: 8.1,
    internet: 8.4
  }
};

const REF_INDEX = 78;

function scaleRange(r, factor) {
  return {
    min: Math.round(r.min * factor),
    max: Math.round(r.max * factor)
  };
}

function scaleCosts(factor) {
  const out = {};
  for (const [k, v] of Object.entries(BASE.costs)) {
    out[k] = scaleRange(v, factor);
  }
  return out;
}

function scaleBudget(factor) {
  return {
    single: scaleRange(BASE.monthlyBudget.single, factor),
    couple: scaleRange(BASE.monthlyBudget.couple, factor),
    family: scaleRange(BASE.monthlyBudget.family, factor)
  };
}

function jitterScore(v, seed) {
  const d = ((seed % 17) - 8) / 10;
  return Math.min(10, Math.max(1, Math.round((v + d) * 10) / 10));
}

function buildCity(meta, i) {
  const factor = meta.costIndex / REF_INDEX;
  const seed = meta.slug.split('').reduce((a, c) => a + c.charCodeAt(0), 0) + i;

  const scores = {};
  for (const [k, v] of Object.entries(BASE.scores)) {
    scores[k] = jitterScore(k === 'housing' ? 10 - meta.costIndex / 15 : v, seed + k.length);
  }
  scores.overall = Math.min(10, Math.max(4, Math.round((scores.housing + scores.safety + scores.culture + scores.economy) / 4 * 10) / 10));

  const hoods = [
    { name: `${meta.name} Center`, type: 'central', rentMultiplier: 1.25, vibe: 'Urban core, transit access' },
    { name: `${meta.name} Midtown`, type: 'central', rentMultiplier: 1.1, vibe: 'Mixed residential' },
    { name: `${meta.name} Outer`, type: 'suburban', rentMultiplier: 0.8, vibe: 'Quieter, family-friendly' }
  ];

  return {
    slug: meta.slug,
    name: meta.name,
    country: meta.country,
    countryCode: meta.countryCode,
    continent: meta.continent,
    currency: meta.currency,
    currencySymbol: meta.currencySymbol,
    usdRate: meta.usdRate,
    teleportSlug: meta.teleportSlug,
    population: meta.population,
    language: meta.language,
    timezone: meta.timezone,
    costIndex: meta.costIndex,
    scores,
    monthlyBudget: scaleBudget(factor),
    costs: scaleCosts(factor),
    neighborhoods: hoods,
    pros: meta.pros,
    cons: meta.cons,
    bestFor: meta.bestFor,
    similarCities: meta.similarCities,
    cheaperAlternatives: meta.cheaperAlternatives,
    description: meta.description,
    lastUpdated: new Date().toISOString().slice(0, 7)
  };
}

